const raw = $input.first().json || {};
const body = raw.body || raw;
const headers = raw.headers || {};
const eventType = String(headers['x-github-event'] || headers['X-GitHub-Event'] || body.event_type || 'github').trim();
const action = String(body.action || 'event').trim();
const sender = body.sender || {};
const repo = body.repository || {};
const issue = body.issue || {};
const pullRequest = body.pull_request || {};
const review = body.review || {};
const htmlUrl = String(pullRequest.html_url || issue.html_url || review.html_url || repo.html_url || '');
const entityID = String(pullRequest.number || issue.number || review.id || headers['x-github-delivery'] || headers['X-GitHub-Delivery'] || 'event').trim();

return [{ json: {
  router_mode: 'intake',
  schema_version: 1,
  source: 'n8n',
  type: 'github_alert',
  project_key: 'pbs',
  title: 'Review PBS GitHub event: ' + eventType + ' ' + action,
  action_key: '',
  dedup_key: 'github_alert:pbs:' + eventType + ':' + action + ':' + entityID,
  requested_by: 'github',
  payload: {
    event_type: eventType,
    action,
    entity_id: entityID,
    repository: String(repo.full_name || ''),
    sender: String(sender.login || ''),
    html_url: htmlUrl,
    raw_event: body
  }
} }];
